def generate_course_correction_plan(
    review: BenefitReviewResult,
    context: str = "",
) -> str:
    """Generate a structured 4-week course correction action plan."""
    client = anthropic.Anthropic()

    action_map = {
        CourseCorrection.ADOPTION_INTERVENTION: "adoption and training intervention",
        CourseCorrection.PROCESS_REDESIGN: "process redesign to remove friction",
        CourseCorrection.PROMPT_TUNING: "prompt engineering and model calibration sprint",
        CourseCorrection.EXEC_ESCALATION: "executive review and potential pivot decision",
        CourseCorrection.MONITOR_ONLY: "continue monitoring (no intervention needed)",
    }
    action_description = action_map[review.recommended_action]

    message = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=400,
        messages=[{"role": "user", "content": f"""
Benefits realization review result for "{review.initiative_id}":
- Weeks live: {review.weeks_since_launch}
- Realization: {review.realization_pct:.0f}% of target
- Adoption: {review.claude_adoption_pct:.0f}%
- Root cause: {review.root_cause}
- Recommended action: {action_description}
- Owner: {review.action_owner}
- Due date: {review.action_due_date}
- Context: {context if context else "None"}

Write a 4-week course correction plan with:
- Week 1: Diagnosis / setup tasks
- Week 2: Implementation
- Week 3: Measurement of early signals
- Week 4: Review and decision (continue / escalate / close)

Each week: 2–3 specific actions with named owners. ≤ 150 words total.
"""}],
    )
    return message.content[0].text

