def detect_benefit_decay(
    tracker,           # BenefitTracker instance
    metric_id: str,
    lookback_weeks: int = 8,
) -> dict:
    """Check if recent performance is trending downward from an earlier peak."""
    obs = sorted(
        [o for o in tracker.observations if o.metric_id == metric_id],
        key=lambda o: o.week_number,
    )
    if len(obs) < lookback_weeks:
        return {"status": "insufficient_data", "weeks_available": len(obs)}

    recent = obs[-lookback_weeks:]
    peak_week = min(obs, key=lambda o: o.value, default=None) \
        if tracker.directions.get(metric_id) == "lower_is_better" \
        else max(obs, key=lambda o: o.value, default=None)

    if peak_week is None:
        return {"status": "no_data"}

    peak_week_num = peak_week.week_number
    peak_value = peak_week.value
    current_value = obs[-1].value
    direction = tracker.directions.get(metric_id, "lower_is_better")

    if direction == "lower_is_better":
        decay = (current_value - peak_value) / abs(peak_value) * 100 if peak_value != 0 else 0
        decaying = decay > 10  # metric worsened > 10% from best observed
    else:
        decay = (peak_value - current_value) / abs(peak_value) * 100 if peak_value != 0 else 0
        decaying = decay > 10

    return {
        "metric_id": metric_id,
        "peak_value": peak_value,
        "peak_week": peak_week_num,
        "current_value": current_value,
        "current_week": obs[-1].week_number,
        "decay_pct": round(decay, 1),
        "decaying": decaying,
        "recommendation": (
            "Investigate: recent performance regressing from peak. "
            "Check adoption rate trend, recent process changes, and staff turnover."
            if decaying else "No decay detected."
        ),
    }
